package ru.kryuch.krtg.searcher.helper;import lombok.Data;import lombok.RequiredArgsConstructor;import org.springframework.stereotype.Component;import org.springframework.web.client.RestTemplate;import java.util.ArrayList;import java.util.List;import java.util.Map;import java.util.Set;@Component@RequiredArgsConstructorpublic class TgHelper {    private final RestTemplate restTemplate;    @Data    class SendResponse {        private int total;        private int success;        private int error;        private List<SendResult> results;    }    @Data    class SendResult {        private Long id;        private String name;        private String username;        private String status;        private String error;    }    public List<String> sendMessage(String message, Set<String> contacts, Boolean notNewFlag) {        String sendUrl = getBaseUrl() + "/api/send_bulk_messages";        Map<String, Object> request = Map.of(                "chat_ids", new ArrayList<>(contacts),                "message_text", message,                "delay_seconds", 4,                "only_new_chats",  notNewFlag        );        SendResponse sendResponse = restTemplate.postForObject(sendUrl, request, SendResponse.class);        return sendResponse.results.stream().map(item -> item.getName()).toList();    }    private String getBaseUrl() {        return "http://localhost:8081";    }}